import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

'use server';

import { redirect } from 'next/navigation';
import { updateTag } from 'next/cache';

import { createPost } from '@/lib/posts';

export async function createPostAction(formData: FormData) {
  const title = formData.get('title');

  if (typeof title !== 'string') {
    throw new Error('Title is required.');
  }

  await createPost(title);

  updateTag('posts');
  redirect('/');
}

import { mkdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { cacheTag } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  createdAt: string;
};

const dataDirectory = path.join(process.cwd(), 'data');
const postsFile = path.join(dataDirectory, 'posts.json');

async function ensurePostsFile() {
  await mkdir(dataDirectory, { recursive: true });

  try {
    await readFile(postsFile, 'utf8');
  } catch {
    await writeFile(postsFile, '[]\n', 'utf8');
  }
}

async function readPostsFromDisk(): Promise<Post[]> {
  await ensurePostsFile();
  const fileContents = await readFile(postsFile, 'utf8');
  return JSON.parse(fileContents) as Post[];
}

async function writePostsToDisk(posts: Post[]) {
  await ensurePostsFile();
  await writeFile(postsFile, `${JSON.stringify(posts, null, 2)}\n`, 'utf8');
}

export async function getPosts() {
  'use cache';

  cacheTag('posts');

  const posts = await readPostsFromDisk();
  return posts.sort((left, right) => right.createdAt.localeCompare(left.createdAt));
}

export async function createPost(title: string) {
  const normalizedTitle = title.trim();

  if (!normalizedTitle) {
    throw new Error('Title is required.');
  }

  const posts = await readPostsFromDisk();

  const post: Post = {
    id: crypto.randomUUID(),
    title: normalizedTitle,
    createdAt: new Date().toISOString(),
  };

  posts.push(post);
  await writePostsToDisk(posts);

  return post;
}

